const express = require('express');
const { Storage } = require('@google-cloud/storage');
const app = express();
const fs = require('fs');

const storage = new Storage({
  projectId: 'YOUR_PROJECT_ID',
  keyFilename: 'path/to/your/service-account-key.json'
});

const bucketName = 'YOUR_BUCKET_NAME';

app.get('/files/:filename*', (req, res) => {
  const filename = req.params.filename;
  const filePath = `/${filename}`;

  storage.bucket(bucketName).file(filePath).exists((err, isExists) => {
    if (!isExists) {
      return res.status(404).send('File Not Found');
    }

    storage.bucket(bucketName).file(filePath).createReadStream().pipe(res);
  });
});

exports.serveFiles = functions.https.onCall((data, context) => {
  return new Promise((resolve, reject) => {
    const filepath = data.filepath;
    app.get('/files/' + filepath, (req, res) => {
      res.pipe(fs.createReadStream(req.file));
    });

    fs.readFile(__dirname + '/' + filepath, (err, buffer) => {
      if (err) return reject(err);
      resolve({content: buffer.toString('base64')});
    });
  });
});